// api-types.ts
export type ApiResponse<T> =
  | { status: 'success'; data: T }
  | { status: 'error'; message: string; code: number }
  | { status: 'pending'; requestId: string };  // new variant

// handlers.ts
function handleResponse<T>(res: ApiResponse<T>): T {
